#!/usr/bin/env bash
APP="$1";NAME="$2";LIVE_DIR=/srv/streaming/live;ARCH_DIR=/srv/streaming/archive;mkdir -p "$LIVE_DIR" "$ARCH_DIR";rm -rf "$LIVE_DIR"/*;OUT="$ARCH_DIR/${NAME}_$(date +%F_%H-%M).mp4";exec /usr/local/bin/ffmpeg -hide_banner -loglevel error -i "rtmp://127.0.0.1/${APP}/${NAME}" -map 0 -c copy "$OUT" -map 0:v -map 0:a -map 0:v -map 0:a -map 0:v -map 0:a -c:v libx264 -preset veryfast -g 48 -keyint_min 48 -sc_threshold 0 -b:v:0 1500k -s:v:0 1280x720 -b:v:1 800k -s:v:1 854x480 -b:v:2 500k -s:v:2 640x360 -c:a aac -ar 44100 -ac 2 -b:a 128k -f hls -hls_time 4 -hls_list_size 6 -hls_flags delete_segments+temp_file -master_pl_name master.m3u8 -var_stream_map "v:0,a:0,name:720p v:1,a:0,name:480p v:2,a:0,name:360p" "$LIVE_DIR/%v/playlist.m3u8"
